// Interfeyslərin sintaksisi
interface Point {
  x: number;
  y: number;
}

let point: Point = {
  x: 10,
  y: 20
};

console.log(point); // { x: 10, y: 20 }
// let invalid: Point = { x: 5 }; // Xəta: y xüsusiyyəti yoxdur

// Interfeyslər vs Tip aliasları
type Id = number | string;

interface User {
  name: string;
}

interface NamedUser extends User {
  id: Id;
}

let user: NamedUser = {
  id: 1,
  name: 'Ali'
};

console.log(user); // { id: 1, name: 'Ali' }
// let invalid: NamedUser = { name: 'Vəli' }; // Xəta: id xüsusiyyəti yoxdur

// Opsiyonel xüsusiyyətlər
interface Person {
  name: string;
  age?: number;
}

let person1: Person = { name: 'Ali' };
let person2: Person = { name: 'Vəli', age: 25 };

console.log(person1); // { name: 'Ali' }
console.log(person2); // { name: 'Vəli', age: 25 }

// Read-only xüsusiyyətlər
interface Product {
  readonly id: number;
  name: string;
}

let product: Product = { id: 1, name: 'Laptop' };
console.log(product); // { id: 1, name: 'Laptop' }
product.name = 'Phone';
console.log(product); // { id: 1, name: 'Phone' }
// product.id = 2; // Xəta: id yalnız oxuna biləndir

// Miras alma
interface Animal {
  name: string;
}

interface Dog extends Animal {
  breed: string;
}

let dog: Dog = {
  name: 'Rex',
  breed: 'Labrador'
};

console.log(dog); // { name: 'Rex', breed: 'Labrador' }
// let invalid: Dog = { breed: 'Husky' }; // Xəta: name xüsusiyyəti yoxdur

// Funksiyalarda interfeyslər
interface User {
  id: number;
  name: string;
}

function printUser(user: User): string {
  return `ID: ${user.id}, Name: ${user.name}`;
}

let user: User = { id: 1, name: 'Ali' };
console.log(printUser(user)); // ID: 1, Name: Ali
// let invalid: User = { id: 2 }; // Xəta: name yoxdur

// Praktik nümunə
interface Order {
  id: number;
  status: 'pending' | 'shipped' | 'delivered';
}

function getOrderInfo(order: Order): string {
  return `Order ${order.id} is ${order.status}`;
}

let order: Order = { id: 1, status: 'pending' };
console.log(getOrderInfo(order)); // Order 1 is pending
order.status = 'delivered';
console.log(getOrderInfo(order)); // Order 1 is delivered
// order.status = 'cancelled'; // Xəta: 'cancelled' status tipinə təyin edilə bilməz

// Təhlükəsizlik nümunəsi
interface Admin {
  name: string;
  role: 'admin';
}

function getAdminInfo(admin: Admin): string {
  return `${admin.name} is ${admin.role}`;
}

let admin: Admin = { name: 'Ali', role: 'admin' };
console.log(getAdminInfo(admin)); // Ali is admin
// let invalid: Admin = { name: 'Vəli' }; // Xəta: role yoxdur

// Səhvə yol açan nümunə
let unsafe: any = { name: 'Ali', role: 'admin' };
console.log(unsafe.name, unsafe.role); // Ali, admin, lakin tip təhlükəsizliyi yoxdur
unsafe = { name: 'Vəli' };
console.log(unsafe.name, unsafe.role); // Vəli, undefined, runtime xətası ola bilər

// Düzgün yol
interface User {
  name: string;
  role: string;
}
let user: User = { name: 'Ali', role: 'admin' };
console.log(user.name, user.role); // Ali, admin
// let invalid: User = { name: 'Vəli' }; // Xəta: role yoxdur

// Real layihə ssenarisi
interface Product {
  id: number;
  name: string;
  price: number;
}

interface DiscountedProduct extends Product {
  discount: number;
}

function calculateFinalPrice(product: DiscountedProduct): number {
  return product.price * product.discount;
}

let product: DiscountedProduct = {
  id: 1,
  name: 'Phone',
  price: 1000,
  discount: 0.9
};

console.log(calculateFinalPrice(product)); // 900

